var pool = global.get('pgPool');
var sensorId = msg.topic.split('/').pop();
var data;
try { data = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; } catch(e) { node.error('Invalid JSON: ' + msg.payload); return null; }
var temp = parseFloat(data.temp_c);
var humidity = parseFloat(data.humidity_pct);
var ts = data.timestamp || new Date().toISOString();
if (isNaN(temp) || isNaN(humidity)) { node.error('Bad values: ' + JSON.stringify(data)); return null; }
var status = 'normal';
if (temp >= 27 || humidity >= 80) status = 'critical';
else if (temp >= 24 || humidity >= 70) status = 'warning';
if (pool) { pool.query('INSERT INTO sensor_readings (sensor_id, sensor_type, reading_ts, value_numeric, value_json, unit) VALUES ($1,$2,$3,$4,$5,$6)', [sensorId, 'temperature', ts, temp, JSON.stringify(data), 'C']).catch(function(e) { node.error('[DB] ' + e.message); }); }
var dashMsg = { topic: 'ems/dashboard/temperature/' + sensorId, payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'temperature', temp_c: temp, humidity_pct: humidity, status: status, timestamp: ts }) };
var alertMsg = null;
if (temp >= 27) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'temperature', metric: 'temp_c', value: temp, threshold: 27, severity: 'critical', message: 'CRITICAL: Temperature ' + temp + 'C exceeds 27C on ' + sensorId, timestamp: ts }) };
else if (temp >= 24) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'temperature', metric: 'temp_c', value: temp, threshold: 24, severity: 'warning', message: 'WARNING: Temperature ' + temp + 'C exceeds 24C on ' + sensorId, timestamp: ts }) };
else if (humidity >= 80) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'temperature', metric: 'humidity_pct', value: humidity, threshold: 80, severity: 'critical', message: 'CRITICAL: Humidity ' + humidity + '% exceeds 80% on ' + sensorId, timestamp: ts }) };
else if (humidity >= 70) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'temperature', metric: 'humidity_pct', value: humidity, threshold: 70, severity: 'warning', message: 'WARNING: Humidity ' + humidity + '% exceeds 70% on ' + sensorId, timestamp: ts }) };
return [dashMsg, alertMsg];

var pool = global.get('pgPool');
var sensorId = msg.topic.split('/').pop();
var data;
try { data = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; } catch(e) { node.error('Invalid JSON: ' + msg.payload); return null; }
var voltage = parseFloat(data.voltage_v) || 0;
var current = parseFloat(data.current_a) || 0;
var power   = parseFloat(data.power_w)   || 0;
var pf      = parseFloat(data.power_factor) || 1;
var energy  = parseFloat(data.energy_kwh)   || 0;
var ts = data.timestamp || new Date().toISOString();
var status = 'normal';
if (pf < 0.75 || current > 100 || voltage < 200 || voltage > 260) status = 'critical';
else if (pf < 0.85 || current > 80) status = 'warning';
if (pool) { pool.query('INSERT INTO sensor_readings (sensor_id, sensor_type, reading_ts, value_numeric, value_json, unit) VALUES ($1,$2,$3,$4,$5,$6)', [sensorId, 'power', ts, power, JSON.stringify(data), 'W']).catch(function(e) { node.error('[DB] ' + e.message); }); }
var dashMsg = { topic: 'ems/dashboard/power/' + sensorId, payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'power', voltage_v: voltage, current_a: current, power_w: power, power_factor: pf, energy_kwh: energy, status: status, timestamp: ts }) };
var alertMsg = null;
if (pf < 0.75) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'power', metric: 'power_factor', value: pf, threshold: 0.75, severity: 'critical', message: 'CRITICAL: Power factor ' + pf + ' below 0.75 on ' + sensorId, timestamp: ts }) };
else if (pf < 0.85) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'power', metric: 'power_factor', value: pf, threshold: 0.85, severity: 'warning', message: 'WARNING: Power factor ' + pf + ' below 0.85 on ' + sensorId, timestamp: ts }) };
else if (current > 100) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'power', metric: 'current_a', value: current, threshold: 100, severity: 'critical', message: 'CRITICAL: Current ' + current + 'A exceeds 100A on ' + sensorId, timestamp: ts }) };
else if (current > 80) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'power', metric: 'current_a', value: current, threshold: 80, severity: 'warning', message: 'WARNING: Current ' + current + 'A exceeds 80A on ' + sensorId, timestamp: ts }) };
return [dashMsg, alertMsg];

