var dashMsg = { topic: 'ems/dashboard/door/' + sensorId, payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'door', state: state, is_open: isOpen, status: isOpen ? 'critical' : 'normal', timestamp: ts }) };
