return [dashMsg, alertMsg];

var pool = global.get('pgPool');
var sensorId = msg.topic.split('/').pop();
var data;
try { data = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; } catch(e) { node.error('Invalid JSON: ' + msg.payload); return null; }
var level   = parseFloat(data.level_pct) || 0;
var alarm   = (data.alarm === true || data.alarm === 'true' || data.alarm === 1);
var gasType = data.gas_type || 'smoke';
var ts      = data.timestamp || new Date().toISOString();
var status  = 'normal';
if (alarm || level >= 50) status = 'critical';
else if (level >= 20) status = 'warning';
if (pool) { pool.query('INSERT INTO sensor_readings (sensor_id, sensor_type, reading_ts, value_numeric, value_json, unit) VALUES ($1,$2,$3,$4,$5,$6)', [sensorId, 'smoke', ts, level, JSON.stringify(data), '%']).catch(function(e) { node.error('[DB] ' + e.message); }); }
var dashMsg = { topic: 'ems/dashboard/smoke/' + sensorId, payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'smoke', level_pct: level, alarm: alarm, gas_type: gasType, status: status, timestamp: ts }) };
var alertMsg = null;
if (alarm || level >= 50) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'smoke', metric: 'level_pct', value: level, threshold: 50, severity: 'critical', message: 'CRITICAL: Smoke/Gas alarm! Level: ' + level + '% (' + gasType + ') on ' + sensorId, timestamp: ts }) };
else if (level >= 20) alertMsg = { topic: 'ems/dashboard/alert', payload: JSON.stringify({ sensor_id: sensorId, sensor_type: 'smoke', metric: 'level_pct', value: level, threshold: 20, severity: 'warning', message: 'WARNING: Smoke/Gas level ' + level + '% exceeds 20% on ' + sensorId, timestamp: ts }) };
return [dashMsg, alertMsg];

